sql.where:
MO.MGMT_OFC_NO = #{mgmtOfcNo}
AND AD.DONG_NO LIKE '%' || #{dong} || '%'
AND AD.HO LIKE '%' || #{ho} || '%'
AND HH.INOUT_CD = #{moveStatus}
AND HH.HEAD_YN = #{headYn}
AND ( M.USER_NO LIKE '%' || #{keyword} || '%' OR M.USER_NM LIKE '%' || #{keyword} || '%' OR M.USER_TELNO LIKE '%' || #{keyword} || '%' OR M.USER_EML LIKE '%' || #{keyword} || '%' OR AD.DONG_NO LIKE '%' || #{keyword} || '%' OR AD.HO LIKE '%' || #{keyword} || '%' )
AND HH.MOVE_IN_DT >= TO_DATE(#{moveInStart}, 'YYYY-MM-DD')
AND HH.MOVE_IN_DT < TO_DATE(#{moveInEnd}, 'YYYY-MM-DD') + 1
AND HH.MOVE_OUT_DT >= TO_DATE(#{moveOutStart}, 'YYYY-MM-DD')
AND HH.MOVE_OUT_DT < TO_DATE(#{moveOutEnd}, 'YYYY-MM-DD') + 1

mapper.select:
SELECT COUNT(*)
FROM HSHLD_HEAD
WHERE USER_NO = #{userNo}
  AND HO_NO = #{hoNo}
